import {
  Component,
  computed,
  signal,
  output,
  input,
  DestroyRef,
  inject,
  OnInit,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { InputTextModule } from 'primeng/inputtext';
import { InputIcon } from 'primeng/inputicon';
import { IconField } from 'primeng/iconfield';
import { TableLazyLoadEvent } from 'primeng/table';
import { debounceTime, Subject } from 'rxjs';
import { ClientListItem } from '../../../api';
import { isEmpty } from '../../utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { GridComponent } from '../grid/grid.component';
import { GridColumn } from '../../models';

@Component({
  selector: 'app-client-selection-form',
  standalone: true,
  imports: [FormsModule, InputTextModule, InputIcon, IconField, GridComponent],
  templateUrl: './client-selection-form.component.html',
  styleUrl: './client-selection-form.component.scss',
})
export class ClientSelectionFormComponent implements OnInit {
  readonly clients = input<ClientListItem[]>([]);
  readonly loading = input<boolean>(false);
  // Whether to use server-side search (true if total clients >= 100)
  readonly useServerSearch = input<boolean>(false);
  readonly totalRecords = input<number>(0);
  readonly enablePagination = input<boolean>(true);
  readonly enableLazyLoad = input<boolean>(false);

  readonly clientSelected = output<string>();
  readonly searchQuery = output<string>();
  readonly lazyLoad = output<TableLazyLoadEvent>();

  private readonly destroyRef = inject(DestroyRef);

  // Search state
  search = signal<string>('');
  private readonly searchChanges$ = new Subject<string>();
  columns = signal<GridColumn[]>([]);

  filteredClients = computed(() => {
    if (this.useServerSearch()) {
      return this.clients();
    }

    const term = this.search().toLowerCase();
    if (isEmpty(term)) return this.clients();
    return this.clients().filter((c) => c.name.toLowerCase().includes(term));
  });

  ngOnInit(): void {
    this.columns.set([{ field: 'name', header: 'Name' }]);
  }

  constructor() {
    this.searchChanges$
      .pipe(debounceTime(300), takeUntilDestroyed(this.destroyRef))
      .subscribe((term) => {
        this.search.set(term.trim());

        if (this.useServerSearch()) {
          this.searchQuery.emit(term.trim());
        }
      });
  }

  onSearchInput(term: string): void {
    this.searchChanges$.next(term);
  }

  selectClient(client: ClientListItem): void {
    if (!client?.id) return;
    this.clientSelected.emit(client.id);
  }

  onLazyLoad(event: TableLazyLoadEvent): void {
    this.lazyLoad.emit(event);
  }
}
