import {
  AfterViewInit,
  ChangeDetectorRef,
  Component,
  computed,
  DestroyRef,
  inject,
  OnInit,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ActivatedRoute, Router } from '@angular/router';

import { firstValueFrom } from 'rxjs';
import { finalize } from 'rxjs/operators';

import { ButtonModule } from 'primeng/button';
import { FilterMetadata, MessageService } from 'primeng/api';
import { TableLazyLoadEvent } from 'primeng/table';

import { WizardComponent } from '../../../../shared/components/wizard/wizard.component';
import { Step } from '../../../../shared/models';
import { UserSessionService } from '../../../../core/services/user-session.service';
import { UserSessionNavigationService } from '../../../../core/services/user-session-navigation.service';
import { AuthTokenManagerService } from '../../../../core/services/auth-token-manager.service';
import { ClientSelectorComponent } from '../../../../shared/components/client-selector/client-selector.component';
import { ClientSelectionFormComponent } from '../../../../shared/components/client-selection-form/client-selection-form.component';
import { hasProperty, isDefined } from '../../../../shared/utils';
import {
  ClientsService,
  ClientListItem,
  AuthUserResponse,
  AuthService,
  ClientResponse,
} from '../../../../api';
import { BroadcastMessageService } from '../../../../core/services/message.service';
import { ActionType } from '../../../../core/models/message.model';
import { DEFAULT_PAGE_SIZE } from '../../../../core/models';
import { UtilityService } from '../../../../core/services/utility.service';
import { AuthDataService } from '../../../../core/services/auth-data.service';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { ThemeComponent } from '../../../../shared/components/theme/theme.component';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { ThemeDataService } from '../../../../shared/services/theme-data.service';
const ROUTES = {
  LOGIN: ['/auth', 'login'],
  POSITION: ['/position'],
  RESET_PASSWORD_WELCOME: ['/auth', 'reset-password-welcome'],
};

const STEPS = {
  SELECT_ACCOUNT: 'Select Account',
  SELECT_CLIENT: 'Select Client',
};

const CONSTANTS = {
  ACTIVE_STATE: 'active',
  CLIENT_TYPE: 'CLIENT',
  SORT_ORDER: 'name:asc',
  FILTER_NAME: 'name',
};

@Component({
  selector: 'app-context-selection-wizard',
  imports: [
    WizardComponent,
    ButtonModule,
    ClientSelectorComponent,
    ClientSelectionFormComponent,
    ThemeComponent,
    ProgressSpinnerModule,
  ],
  templateUrl: './context-selection-wizard.component.html',
  styleUrl: './context-selection-wizard.component.scss',
})
export class ContextSelectionWizardComponent implements AfterViewInit, OnInit {
  @ViewChild('accountSelectionStep') accountSelectionStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild('clientSelectionStep') clientSelectionStep!: TemplateRef<{
    $implicit: Step;
  }> | null;
  @ViewChild(WizardComponent) wizard!: WizardComponent;

  private readonly userSessionService = inject(UserSessionService);
  private readonly userSessionNavigationService = inject(
    UserSessionNavigationService,
  );
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly apiAuthService = inject(AuthService);
  private readonly authTokenManager = inject(AuthTokenManagerService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly clientsService = inject(ClientsService);
  private readonly messageService = inject(BroadcastMessageService);
  private readonly utilityService = inject(UtilityService);
  private readonly authDataService = inject(AuthDataService);
  private readonly themeService = inject(ThemeDataService);
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly destroyRef = inject(DestroyRef);
  private readonly uiMessageService = inject(MessageService);

  accounts = this.userSessionService.userSessions();
  selectedAccount = signal<AuthUserResponse | null>(null);
  availableClients = signal<ClientListItem[]>([]);
  totalClientCount = signal<number>(0);
  loadingClients = signal<boolean>(false);
  loadingPreviewTheme = signal<boolean>(false);
  isAutoSelectingAccount = signal<boolean>(false);
  isPasswordResetMode = false;
  returnUrl: string | null = null;
  isSubmitting = signal<boolean>(false);
  private clientsOffset = 0;
  private readonly pageSize = DEFAULT_PAGE_SIZE;
  private currentSearchTerm = '';
  private cachedEmptyClients: ClientListItem[] = [];
  private cachedEmptyTotal = 0;
  private cachedEmptyOffset = 0;

  readonly currentYear = new Date().getFullYear();

  // Determine if we should use server-side search based on total count
  useServerSearch = computed(
    () => this.totalClientCount() >= DEFAULT_PAGE_SIZE,
  );

  // Overall loading state - combines submission and theme preview loading
  isLoading = computed(() => this.isSubmitting() || this.loadingPreviewTheme());

  steps: Step[] = [];

  ngOnInit(): void {
    // Check if we're in password reset mode
    const resetPassword = this.route.snapshot.queryParams['resetPassword'];
    this.isPasswordResetMode = resetPassword === 'true';

    // Capture return URL if present
    this.returnUrl = this.route.snapshot.queryParams['returnUrl'] ?? null;
  }

  ngAfterViewInit() {
    // Only show account selection step if there are multiple accounts
    const steps: Step[] = [];
    let nextValue = 1;
    if (this.accounts.length > 1) {
      steps.push({
        value: nextValue++,
        header: STEPS.SELECT_ACCOUNT,
        content: this.accountSelectionStep,
        complete: false,
        disableNext: true,
      });
    }
    steps.push({
      value: nextValue,
      header: STEPS.SELECT_CLIENT,
      content: this.clientSelectionStep,
      complete: false,
      disableNext: true,
    });
    this.steps = steps;
    this.cdr.detectChanges();

    // CRITICAL: Guard against empty accounts list (initialization failure)
    // If no accounts available after resolver completed, redirect to login
    if (this.accounts.length === 0) {
      this.navigateToLogin();
      return;
    }

    // Load initial preview theme from first account's default client
    // This ensures theme is set immediately for multi-account users
    const firstAccount = this.accounts[0];
    if (firstAccount?.defaultClient?.id) {
      this.loadingPreviewTheme.set(true);
      this.clientsService
        .getClient(firstAccount.defaultClient.id)
        .pipe(
          takeUntilDestroyed(this.destroyRef),
          finalize(() => this.loadingPreviewTheme.set(false)),
        )
        .subscribe({
          next: (client) => {
            this.clientDataService.setPreviewClient(client);
          },
          error: (error) => {
            console.warn('Failed to load initial preview client:', error);
            // Continue without preview - not critical
          },
        });
    }

    // Smart Redirection: If only one account, auto-select it
    if (this.accounts.length === 1) {
      this.isAutoSelectingAccount.set(true);
      this.userSessionNavigationService
        .navigateBasedOnSessions(this.accounts, this.returnUrl)
        .then<void>((navigated: boolean) => {
          if (!navigated) {
            // If navigation didn't happen (e.g. stayed on wizard), manually select
            void this.onAccountSelected(this.accounts[0]);
          }
        })
        .catch((error: unknown) =>
          console.error('Error auto-selecting account:', error),
        )
        .finally(() => this.isAutoSelectingAccount.set(false));
    }
  }

  async onAccountSelected(account: AuthUserResponse): Promise<void> {
    this.selectedAccount.set(account);
    this.clearSessionState();
    this.isSubmitting.set(true);

    try {
      if (this.isPasswordResetMode) {
        this.userSessionService.setCurrentUserSession(account.id);
        this.isSubmitting.set(false);
        await this.router.navigate(ROUTES.RESET_PASSWORD_WELCOME);
        return;
      }

      // If only one account, skip re-authentication (tokens likely valid)
      // BUT proceed to client selection flow to handle auto-redirects
      if (this.accounts.length === 1) {
        this.userSessionService.setCurrentUserSession(account.id);
      } else {
        await this.authenticateUser(account);
      }

      if (await this.handleReturnUrl()) {
        this.isSubmitting.set(false);
        return;
      }

      await this.handleClientSelectionFlow(account);
    } catch (error) {
      console.error('Error selecting user:', error);
      this.uiMessageService.add({
        severity: 'error',
        summary: 'Error',
        detail: 'Failed to select account. Please try again.',
      });
      this.isSubmitting.set(false);
    }
  }

  private clearSessionState(): void {
    this.clientDataService.clearSelectedClient();
    this.clientDataService.clearPreviewClient();
    this.themeService.clearTheme();
  }

  private async authenticateUser(account: AuthUserResponse): Promise<void> {
    const response = await firstValueFrom(
      this.apiAuthService.selectUser(account.id),
    );

    this.authTokenManager.storeTokens({
      accessToken: response.accessToken,
      refreshToken: response.refreshToken,
      idToken: response.idToken ?? '',
      users: this.accounts,
    });

    const profile = await firstValueFrom(this.apiAuthService.getUserProfile());
    if (isDefined(profile)) {
      await this.authDataService.setUserProfile(profile);
    }

    this.userSessionService.setCurrentUserSession(account.id);
  }

  private async handleReturnUrl(): Promise<boolean> {
    if (
      isDefined(this.returnUrl) &&
      this.returnUrl !== null &&
      this.returnUrl.trim() !== ''
    ) {
      await this.router.navigateByUrl(this.returnUrl);
      return true;
    }
    return false;
  }

  private async handleClientSelectionFlow(
    account: AuthUserResponse,
  ): Promise<void> {
    const ownerType = account?.owner?.type?.toUpperCase();
    const isClientOnlyUser = ownerType === CONSTANTS.CLIENT_TYPE;
    const defaultClientId = account?.defaultClient?.id;
    const hasSingleDefaultClient =
      isClientOnlyUser && isDefined(defaultClientId);

    if (isDefined(defaultClientId)) {
      this.loadPreviewTheme(defaultClientId);
    }

    if (!hasSingleDefaultClient) {
      this.loadClientsForAccount();
    }

    if (hasSingleDefaultClient) {
      this.attemptAutoSelectClient(defaultClientId);
    } else {
      await this.enableClientSelectionStep();
      this.isSubmitting.set(false);
    }
  }

  private loadPreviewTheme(clientId: string): void {
    this.loadingPreviewTheme.set(true);
    this.clientsService
      .getClient(clientId)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.loadingPreviewTheme.set(false)),
      )
      .subscribe({
        next: (client) => {
          this.clientDataService.setPreviewClient(client);
        },
        error: (error) => {
          console.warn('Failed to load preview client for theming:', error);
        },
      });
  }

  private attemptAutoSelectClient(clientId: string): void {
    this.clientsService
      .getClient(clientId)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        finalize(() => this.isSubmitting.set(false)),
      )
      .subscribe({
        next: (client) => {
          this.finalizeClientSelection(client);
        },
        error: () => {
          void this.enableClientSelectionStep();
        },
      });
  }

  private finalizeClientSelection(client: ClientResponse): void {
    this.clientDataService.clearPreviewClient();
    this.messageService.sendAction(ActionType.profile_changed, {
      clientId: client.id,
    });
    this.clientDataService.setSelectedClient(client);
    this.router.navigate(ROUTES.POSITION).catch(() => {});
  }

  private async enableClientSelectionStep(): Promise<void> {
    if (Array.isArray(this.steps) && this.steps.length > 1) {
      this.steps[0].complete = true;
      this.steps[1].disableNext = false;
      await this.wizard.goNext();
    }
  }

  loadClientsForAccount(searchTerm = ''): void {
    this.clientsOffset = 0;
    this.currentSearchTerm = searchTerm;

    // Restore cached empty-search pages when clearing search
    if (searchTerm.trim() === '' && this.cachedEmptyClients.length > 0) {
      this.availableClients.set(this.cachedEmptyClients);
      this.totalClientCount.set(this.cachedEmptyTotal);
      this.clientsOffset = this.cachedEmptyOffset;
      this.loadingClients.set(false);
      this.cdr.detectChanges();
      return;
    }

    // Use the currently selected account's owner ID, not the user profile
    // This ensures we use the correct owner for the newly selected account
    const selectedAccount = this.selectedAccount();
    if (!isDefined(selectedAccount?.owner?.id)) {
      console.warn('Owner ID not found in selected account');
      this.fallbackToDefaultClient();
      return;
    }

    const ownerId = selectedAccount.owner.id;
    const filters: Record<
      string,
      FilterMetadata | FilterMetadata[] | string | undefined
    > = {
      state: {
        value: CONSTANTS.ACTIVE_STATE,
        operator: '=',
      },
    };

    // Add search filter if provided
    if (searchTerm.trim() !== '') {
      filters[CONSTANTS.FILTER_NAME] = {
        value: `*${searchTerm}*`,
        operator: '=',
      };
    }

    this.loadingClients.set(true);

    const rqlFilter = this.utilityService.constructRqlFilter(filters);

    this.clientsService
      .listClients(ownerId, 0, this.pageSize, CONSTANTS.SORT_ORDER, rqlFilter)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (data) => {
          if (
            isDefined(data) &&
            hasProperty(data, 'items') &&
            hasProperty(data, 'count')
          ) {
            const items = data.items ?? [];
            this.availableClients.set(items);
            this.clientsOffset = 0;
            this.totalClientCount.set(data.count);

            if (searchTerm.trim() === '') {
              // Cache empty-search pages to restore when clearing search
              this.cachedEmptyClients = items;
              this.cachedEmptyTotal = data.count ?? items.length;
              this.cachedEmptyOffset = 0;
            }
          } else {
            console.warn('Invalid response data structure');
          }
          this.loadingClients.set(false);
          this.cdr.detectChanges();
        },
        error: () => {
          this.loadingClients.set(false);
          this.fallbackToDefaultClient();
        },
      });
  }

  onClientSearch(searchTerm: string): void {
    this.currentSearchTerm = searchTerm;
    // Only trigger server search if we have >= 100 clients
    if (this.useServerSearch()) {
      // Trigger lazy load from the beginning with the new search term
      this.onLazyLoadClients({ first: 0, rows: this.pageSize });
    }
    // Otherwise, client-side filtering happens automatically in the component
  }

  onLazyLoadClients(event: TableLazyLoadEvent): void {
    // Grid pagination event - load the requested page
    const offset = event.first ?? 0;
    const ownerId = this.selectedAccount()?.owner?.id;

    if (!isDefined(ownerId)) {
      console.warn('Owner ID not found in selected account');
      this.fallbackToDefaultClient();
      return;
    }

    const filters: Record<
      string,
      FilterMetadata | FilterMetadata[] | string | undefined
    > = {
      state: {
        value: CONSTANTS.ACTIVE_STATE,
        operator: '=',
      },
    };

    if (this.currentSearchTerm.trim() !== '') {
      filters[CONSTANTS.FILTER_NAME] = {
        value: `*${this.currentSearchTerm}*`,
        operator: '=',
      };
    }

    this.loadingClients.set(true);
    const rqlFilter = this.utilityService.constructRqlFilter(filters);
    const pageSize = event.rows ?? this.pageSize;

    this.clientsService
      .listClients(ownerId, offset, pageSize, CONSTANTS.SORT_ORDER, rqlFilter)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (data) => {
          if (
            isDefined(data) &&
            hasProperty(data, 'items') &&
            hasProperty(data, 'count')
          ) {
            this.availableClients.set(data.items ?? []);
            this.totalClientCount.set(data.count);
            this.clientsOffset = offset;
          } else {
            console.warn('Invalid response data structure');
          }
          this.loadingClients.set(false);
          this.cdr.detectChanges();
        },
        error: () => {
          this.uiMessageService.add({
            severity: 'error',
            summary: 'Error',
            detail: 'Failed to load clients.',
          });
          this.loadingClients.set(false);
        },
      });
  }

  async onClientSelected(clientId: string): Promise<void> {
    if (!clientId) return;
    this.isSubmitting.set(true);
    this.clientsService
      .getClient(clientId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.finalizeClientSelection(response);
          this.isSubmitting.set(false);
        },
        error: (error) => {
          console.error('Error selecting client:', error);
          this.uiMessageService.add({
            severity: 'error',
            summary: 'Error',
            detail: 'Failed to select client.',
          });
          this.isSubmitting.set(false);
        },
      });
  }

  onWizardCancel(): void {
    this.clientDataService.clearPreviewClient();
    this.navigateToLogin();
  }

  private navigateToLogin(): void {
    this.userSessionService.clearAllSessions();
    this.router
      .navigate(ROUTES.LOGIN)
      .catch((error) => console.error('Error navigating to login:', error));
  }

  /**
   * Fallback mechanism when client loading fails
   * Attempts to proceed with the default client if available
   */
  private fallbackToDefaultClient(): void {
    const selectedAccount = this.selectedAccount();
    const defaultClientId = selectedAccount?.defaultClient?.id;

    if (isDefined(defaultClientId)) {
      console.warn(
        'Attempting to proceed with default client due to loading failure',
      );
      this.isSubmitting.set(true);
      this.clientsService
        .getClient(defaultClientId)
        .pipe(
          takeUntilDestroyed(this.destroyRef),
          finalize(() => this.isSubmitting.set(false)),
        )
        .subscribe({
          next: (client) => {
            this.uiMessageService.add({
              severity: 'info',
              summary: 'Notice',
              detail: 'Proceeding with your default client.',
            });
            this.finalizeClientSelection(client);
          },
          error: (error) => {
            console.error('Failed to load default client:', error);
            this.uiMessageService.add({
              severity: 'error',
              summary: 'Error',
              detail: 'Unable to proceed. Please contact support.',
            });
          },
        });
    } else {
      console.warn('No default client available for fallback');
    }
  }
}
